// OAuth 2.0 client for managing access and refresh tokens in browser localStorage
class OAuthClient {
  constructor() {
    this.accessToken = null;
    this.refreshToken = null;
  }

  // Store access and refresh tokens in browser localStorage
  storeTokens(accessToken, refreshToken) {
    localStorage.setItem('accessToken', accessToken);
    localStorage.setItem('refreshToken', refreshToken);
  }

  // Retrieve access and refresh tokens from browser localStorage
  retrieveTokens() {
    this.accessToken = localStorage.getItem('accessToken');
    this.refreshToken = localStorage.getItem('refreshToken');
  }

  // Automatically refresh the access token when it expires
  async refreshAccessToken() {
    const refreshToken = await this.retrieveRefreshToken();
    if (refreshToken) {
      try {
        const response = await fetch('/token', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            grant_type: 'refresh_token',
            refresh_token: refreshToken,
            client_id: 'your_client_id',
            client_secret: 'your_client_secret'
          })
        });
        const data = await response.json();
        this.storeTokens(data.access_token, data.refresh_token);
      } catch (error) {
        console.log('Error refreshing access token:', error);
      }
    }
  }

  // Retrieve the refresh token from browser localStorage
  async retrieveRefreshToken() {
    return localStorage.getItem('refreshToken');
  }

  // Get the current access token
  getAccessToken() {
    return this.accessToken;
  }
}